import React, { useState, useEffect } from 'react';
import { api } from '../services/api'; 
import { useAuth } from '../context/AuthContext';
import { Package, MapPin, CheckCircle, Truck, Loader2, Bike, Store } from 'lucide-react';

const MisPedidosCliente = ({ userCoords }) => {
  const [pedidos, setPedidos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [progresoEnvio, setProgresoEnvio] = useState({}); 
  const { user } = useAuth();

  useEffect(() => {
    const fetchPedidos = async () => {
      try {
        const clienteId = user?.id || user?._id;
        if (!clienteId) return;
        const data = await api.getPedidosCliente(clienteId);
        setPedidos(Array.isArray(data) ? data : []);
      } catch (error) {
        console.error("Error al obtener historial:", error);
      } finally {
        setLoading(false);
      }
    };
    if (user) fetchPedidos();
  }, [user]);

  useEffect(() => {
    pedidos.forEach(pedido => {
      if (pedido.estado?.toLowerCase() === 'camino' && !progresoEnvio[pedido._id]) {
        iniciarSimulacionRealista(pedido);
      }
    });
  }, [pedidos]);

  const iniciarSimulacionRealista = (pedido) => {
    let progreso = 0;
    // 1. Tiempo de preparación (fijo 10s para demo) + Tiempo de viaje (dinámico)
    const tiempoViajeBase = 20; 
    const interval = setInterval(() => {
      progreso += 1;
      setProgresoEnvio(prev => ({ ...prev, [pedido._id]: progreso }));

      if (progreso >= 100) {
        clearInterval(interval);
        // Opcional: api.actualizarEstadoPedido(pedido._id, 'completado');
      }
    }, (tiempoViajeBase * 1000) / 100);
  };

  return (
    <div style={container}>
      <h2 style={title}>Seguimiento en Vivo</h2>
      <div style={listContainer}>
        {pedidos.map((pedido) => {
          const p = progresoEnvio[pedido._id] || (pedido.estado === 'completado' ? 100 : 0);
          
          return (
            <div key={pedido._id} style={orderCard}>
              {/* --- CABECERA --- */}
              <div style={orderHeader}>
                <span style={dateText}>Pedido #{pedido._id?.slice(-5)}</span>
                <span style={{...statusText, color: p === 100 ? '#22c55e' : '#3182ce'}}>
                   {p === 100 ? 'ENTREGADO' : pedido.estado?.toUpperCase()}
                </span>
              </div>

              {/* --- BARRA DE 3 SEPARACIONES --- */}
              <div style={stepperWrapper}>
                <div style={stepperBackground}>
                  <div style={{...stepperFill, width: `${p}%`}} />
                </div>
                
                <div style={nodesContainer}>
                  {/* Etapa 1: Local */}
                  <div style={nodeGroup}>
                    <div style={{...node, backgroundColor: p >= 5 ? '#3182ce' : '#e2e8f0'}}>
                      <Store size={14} color="white" />
                    </div>
                    <span style={nodeLabel}>Local</span>
                  </div>

                  {/* Etapa 2: Cadete */}
                  <div style={nodeGroup}>
                    <div style={{...node, backgroundColor: p >= 50 ? '#3182ce' : '#e2e8f0'}}>
                      <Bike size={14} color="white" />
                    </div>
                    <span style={nodeLabel}>En camino</span>
                  </div>

                  {/* Etapa 3: Entregado */}
                  <div style={nodeGroup}>
                    <div style={{...node, backgroundColor: p >= 100 ? '#22c55e' : '#e2e8f0'}}>
                      <CheckCircle size={14} color="white" />
                    </div>
                    <span style={nodeLabel}>¡Llegó!</span>
                  </div>
                </div>

                {/* Icono flotante del camión siguiendo el progreso */}
                {p > 0 && p < 100 && (
                  <div style={{...truckFloat, left: `calc(${p}% - 15px)`}}>
                    <Truck size={18} color="#3182ce" />
                  </div>
                )}
              </div>

              {/* --- CUERPO --- */}
              <div style={bodyCard}>
                <div style={localRow}>
                  <div style={avatarLocal}>{pedido.local?.nombre?.charAt(0)}</div>
                  <div>
                    <h4 style={localName}>{pedido.local?.nombre}</h4>
                    <p style={localAddr}><MapPin size={12} /> {pedido.local?.direccion}</p>
                  </div>
                </div>

                <div style={itemsBox}>
                  {pedido.items?.map((item, i) => (
                    <div key={i} style={itemLine}>
                      <span>{item.cantidad}x {item.producto}</span>
                      <span>${item.precio * item.cantidad}</span>
                    </div>
                  ))}
                </div>

                <div style={priceFooter}>
                  <div style={priceRow}><span>Envío</span><span>${pedido.costoEnvio || 800}</span></div>
                  <div style={{...priceRow, fontWeight: '900', fontSize: '1.1rem', marginTop: '5px', color: '#1e293b'}}>
                    <span>Total Pagado</span>
                    <span>${pedido.total}</span>
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

// --- DISEÑO DETALLISTA (CSS-in-JS) ---
const container = { padding: '20px', maxWidth: '500px', margin: '0 auto', fontFamily: 'Inter, system-ui, sans-serif' };
const title = { fontSize: '1.6rem', fontWeight: '800', color: '#0f172a', marginBottom: '25px', letterSpacing: '-0.02em' };
const listContainer = { display: 'flex', flexDirection: 'column', gap: '25px' };
const orderCard = { background: '#fff', borderRadius: '28px', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.05), 0 8px 10px -6px rgba(0,0,0,0.05)', border: '1px solid #f1f5f9', position: 'relative' };
const orderHeader = { padding: '18px 24px', display: 'flex', justifyContent: 'space-between', borderBottom: '1px solid #f8fafc' };
const dateText = { color: '#94a3b8', fontSize: '0.85rem', fontWeight: '600' };
const statusText = { fontSize: '0.85rem', fontWeight: '800' };

// ESTILOS DEL STEPPER (BARRA DE 3)
const stepperWrapper = { padding: '40px 40px 20px 40px', position: 'relative' };
const stepperBackground = { height: '4px', background: '#f1f5f9', borderRadius: '10px', position: 'relative' };
const stepperFill = { height: '100%', background: '#3182ce', borderRadius: '10px', transition: 'width 0.4s ease' };
